import React, {useState} from "react";
import './Welcome.css';

function Welcome () {
    const [userName, setUserName] = useState('');
    const [passWord, setPassWord] = useState('');
    const [isLoginSuccessful, setIsLoginSuccessful] = useState(false);
    const handleUsernameChange = (e) => {
        const value = e.target.value;
        setUserName(value);
    }
    const handlePasswordChange = (e) => {
        const value = e.target.value;
        setPassWord(value);
    }
    const Login = () => {

        if (userName === 'admin' && passWord === '1234') {
            console.log('Success!!!!!!')
        }
        else
        console.log('Failed!!!!!!')
        isLoginSuccessful(false);

}
    return  (
    <div>
        <h1 className = 'title'>Welcome to Productiv!</h1>
        <Credentials isLoginSuccessful = {isLoginSuccessful}></Credentials>
       <ValidCreds setIsLoginSuccessful = {setIsLoginSuccessful}></ValidCreds>
        <form className = 'location-form'>
            <div>
            <label htmlFor="username">Username </label>
            <input type="text" id="username" name="username" value = {userName} onChange = {handleUsernameChange}></input>
            </div>
            <div>
            <label htmlFor="password">Password </label>
            <input type="password" id="password" name="password" value = {passWord} onChange = {handlePasswordChange}></input>
            </div>
            <div>
            <button className ='button' type="submit" value= "Log in" onClick={Login}>Login</button>
            <button className ='button' type="submit" value= "Sign up">Sign up</button>
            </div>
        </form>
    </div>
    )
    function Credentials (props) {
        if (props.isLoginSuccessful) {
            return <div>Invalid Credentials</div>
        }
        return null;
    }
    function ValidCreds (props) {
        if (props.setIsLoginSuccessful) {
            return <div>Congrats!</div>
        }
        return null;
    }
    }

export default Welcome;
